1	import { promises as fs } from "fs"
2	import path from "path"
3	import { ExamplesIndex } from "@/examples/__index__"
4	import { LRUCache } from "lru-cache"
5	import { registryItemSchema, type registryItemFileSchema } from "shadcn/schema"
6	import { type z } from "zod"
