### Complete Registry Item Schema (TypeScript)

From `/packages/shadcn/src/registry/schema.ts`:

```typescript
// Common fields for ALL registry items
{
  name: string;                                    // Required, unique ID
  type: RegistryItemType;                          // Required
  title?: string;                                  // Human-readable title
  description?: string;                            // Brief description
  author?: string;                                 // "Name <email>"

  // Dependencies
  dependencies?: string[];                         // npm packages (can include @version)
  devDependencies?: string[];                      // Dev npm packages
  registryDependencies?: string[];                 // Other registry items (names/urls)

  // Files
  files?: Array<{
    path: string;                                  // Path to file in registry
    content?: string;                              // Optional inline content
    type: RegistryItemType;                        // File-level type
    target?: string;                               // Where to install (required for registry:page/file)
  }>;

  // Styling & CSS
  tailwind?: {
    config?: {
      content?: string[];
      theme?: Record<string, any>;
      plugins?: string[];
    };
  };

  cssVars?: {
    theme?: Record<string, string>;                // Global CSS vars
    light?: Record<string, string>;                // Light theme vars
    dark?: Record<string, string>;                 // Dark theme vars
  };

  css?: Record<string, CssValue>;                  // Raw CSS rules (@layer, @keyframes, etc)

  // Environment & Metadata
  envVars?: Record<string, string>;                // Environment variables
  meta?: Record<string, any>;                      // Custom metadata
  docs?: string;                                   // Markdown documentation
  categories?: string[];                           // Organization tags

  // Font-specific (type: "registry:font")
  font?: {
    family: string;                                // e.g., "Inter Variable, sans-serif"
    provider: "google";                            // Currently only "google"
    import: string;                                // Import name from next/font/google
    variable: string;                              // CSS variable name
    weight?: string[];                             // Font weights
    subsets?: string[];                            // Font subsets
    selector?: string;                             // CSS selector to apply to
    dependency?: string;                           // npm package for non-Next.js
  };

  // Base-specific (type: "registry:base")
  extends?: string;                                // Base to extend
  config?: RawConfigSchema;                        // Design system config
  style?: string;
  iconLibrary?: string;
  baseColor?: string;
  theme?: string;
}
```

