    },
  ],
  meta: {
    links: {
      docs: "https://ui.shadcn.com/docs/components/base/dropdown-menu",
      examples: "https://raw.githubusercontent.com/...",
      api: "https://base-ui.com/react/components/dropdown-menu.md",
    },
  },
