input.content:
"use client"

import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

type StepperContextValue = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: "horizontal" | "vertical"
  totalSteps: number
  setTotalSteps: React.Dispatch<React.SetStateAction<number>>
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a Stepper.")
  }
  return context
}

// ---------------------------------------------------------------------------
// Item Context – tracks the index of a particular StepperItem
// ---------------------------------------------------------------------------

type StepperItemContextValue = {
  step: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a StepperItem.")
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper (root)
// ---------------------------------------------------------------------------

function Stepper({
  activeStep = 0,
  onActiveStepChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep?: number
  onActiveStepChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [internalStep, setInternalStep] = React.useState(activeStep)
  const [totalSteps, setTotalSteps] = React.useState(0)

  const currentStep = onActiveStepChange ? activeStep : internalStep

  const setActiveStepFn = React.useCallback(
    (step: number) => {
      if (onActiveStepChange) {
        onActiveStepChange(step)
      } else {
        setInternalStep(step)
      }
    },
    [onActiveStepChange]
  )

  const contextValue = React.useMemo<StepperContextValue>(
    () => ({
      activeStep: currentStep,
      setActiveStep: setActiveStepFn,
      orientation,
      totalSteps,
      setTotalSteps,
    }),
    [currentStep, setActiveStepFn, orientation, totalSteps]
  )

  return (
    <StepperContext.Provider value={contextValue}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex",
          orientation === "horizontal"
            ? "flex-row items-center"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

let stepCounter = 0

function StepperItem({
  step,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  disabled?: boolean
}) {
  const { activeStep, totalSteps, setTotalSteps, orientation } = useStepper()

  React.useEffect(() => {
    setTotalSteps((prev) => Math.max(prev, step + 1))
  }, [step, setTotalSteps])

  const isActive = activeStep === step
  const isCompleted = activeStep > step

  const itemContextValue = React.useMemo<StepperItemContextValue>(
    () => ({
      step,
      isActive,
      isCompleted,
      isDisabled: disabled,
    }),
    [step, isActive, isCompleted, disabled]
  )

  return (
    <StepperItemContext.Provider value={itemContextValue}>
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
        data-disabled={disabled ? "" : undefined}
        data-orientation={orientation}
        className={cn(
          "cn-stepper-item group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-row items-center"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep, orientation } = useStepper()
  const { step, isActive, isCompleted, isDisabled } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      data-disabled={isDisabled ? "" : undefined}
      data-orientation={orientation}
      type="button"
      disabled={isDisabled}
      className={cn(
        "cn-stepper-trigger inline-flex items-center gap-3 rounded-md bg-transparent text-left outline-none transition-colors",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => setActiveStep(step)}
      {...props}
    >
      {children ?? (
        <StepperIndicator>
          {isCompleted ? (
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="16"
              height="16"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <polyline points="20 6 9 17 4 12" />
            </svg>
          ) : (
            step + 1
          )}
        </StepperIndicator>
      )}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperIndicator – a small circle showing the step number / icon
// ---------------------------------------------------------------------------

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { isActive, isCompleted } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      className={cn(
        "cn-stepper-indicator inline-flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium transition-colors",
        isActive &&
          "border-primary bg-primary text-primary-foreground",
        isCompleted &&
          "border-primary bg-primary text-primary-foreground",
        !isActive &&
          !isCompleted &&
          "border-muted-foreground/25 bg-transparent text-muted-foreground",
        className
      )}
      {...props}
    >
      {children}
    </span>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { isActive, isCompleted } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      className={cn(
        "cn-stepper-title text-sm font-medium leading-none",
        (isActive || isCompleted) && "text-foreground",
        !isActive && !isCompleted && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-sm text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { isCompleted } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-state={isCompleted ? "completed" : "inactive"}
      data-orientation={orientation}
      role="separator"
      className={cn(
        "cn-stepper-separator transition-colors",
        orientation === "horizontal"
          ? "mx-2 h-px flex-1 self-center"
          : "ml-4 mt-1 mb-1 w-px self-stretch",
        isCompleted ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent – panel shown for the active step
// ---------------------------------------------------------------------------

function StepperContent({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  const { isActive } = useStepperItem()

  if (!isActive) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn(
        "cn-stepper-content",
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepper,
}

